#!/usr/bin/env python3
import base64, os, subprocess

b64_gtm = ""
os.makedirs(os.path.dirname("/var/www/konverta/src/gtm-export.js"), exist_ok=True)
open("/var/www/konverta/src/gtm-export.js", "wb").write(base64.b64decode(b64_gtm))
print("✓ /var/www/konverta/src/gtm-export.js")

b64_collect = ""
os.makedirs(os.path.dirname("/var/www/konverta/src/routes/collect.js"), exist_ok=True)
open("/var/www/konverta/src/routes/collect.js", "wb").write(base64.b64decode(b64_collect))
print("✓ /var/www/konverta/src/routes/collect.js")

b64_admin = ""
os.makedirs(os.path.dirname("/var/www/konverta/src/routes/admin/index.js"), exist_ok=True)
open("/var/www/konverta/src/routes/admin/index.js", "wb").write(base64.b64decode(b64_admin))
print("✓ /var/www/konverta/src/routes/admin/index.js")

print("\n✅ client_id corrigido!")
subprocess.run(["pm2", "restart", "konverta"])